        inventory = {'apple': 5, 'banana': 10}
        prices = {'apple': 2.0}
        # (5 * 2.0) + (10 * 0) = 10
        self.assertEqual(total_value(inventory, prices), 10.0)

if __name__ == '__main__':
    unittest.main()

